mapper.select:
SELECT A.DOC_NO docNo,U.UNIT_CODE unitCode, U.UNIT_NAME unitName, C.WAREHOUSE_CODE warehouseCode, D.ITEM_CODE itemCode,D.ITEM_NAME itemName,D.ITEM_SPECIFICATION itemSpec, SUM(B.BUSINESS_QTY) planQty,SUM(B.ISSUED_QTY) deliveryQty,SUM(B.BUSINESS_QTY-B.ISSUED_QTY) unDeliveryQty, Z.UDF021 binCode, (SELECT TOP 1 CUSTOMER_ORDER_NO FROM SALES_ORDER_DOC X LEFT JOIN SALES_ORDER_DOC_D Y ON X.SALES_ORDER_DOC_ID=Y.SALES_ORDER_DOC_ID LEFT JOIN SALES_ORDER_DOC_SD Z ON Y.SALES_ORDER_DOC_D_ID=Z.SALES_ORDER_DOC_D_ID LEFT JOIN SALES_DELIVERY_D K ON Z.SALES_ORDER_DOC_SD_ID=K.SOURCE_ID_ROid WHERE K.SALES_DELIVERY_ID=A.SALES_DELIVERY_ID) customerNo, P.PLANT_CODE shjg FROM SALES_DELIVERY A LEFT JOIN SALES_DELIVERY_D B ON A.SALES_DELIVERY_ID=B.SALES_DELIVERY_ID LEFT JOIN WAREHOUSE C ON B.WAREHOUSE_ID = C.WAREHOUSE_ID LEFT JOIN ITEM D ON D.ITEM_BUSINESS_ID = B.ITEM_ID LEFT JOIN ITEM_PLANT Z ON Z.ITEM_ID = D.ITEM_BUSINESS_ID LEFT JOIN UNIT U ON D.STOCK_UNIT_ID = U.UNIT_ID LEFT JOIN PLANT P ON P.PLANT_ID = A.PLANT_ID WHERE B.BUSINESS_QTY-B.ISSUED_QTY>0 AND A.DOC_NO IN
#{docNo}
AND C.WAREHOUSE_CODE IN
#{warehouseCode}
AND ISNULL(ITEM_CODE,'') <> '' GROUP BY D.ITEM_CODE,D.ITEM_NAME,D.ITEM_SPECIFICATION,C.WAREHOUSE_CODE,U.UNIT_NAME,U.UNIT_CODE,A.DOC_NO,Z.UDF021,A.SALES_DELIVERY_ID,P.PLANT_CODE ORDER BY D.ITEM_CODE

SELECT id, item_code itemCode, business_qty businessQty, item_name itemName, item_spec itemSpec,
       create_by createBy, create_time createTime, match_qty matchQty, doc_no docNo, unit_no unitNo,
       bin_code binCode, warehouse_code warehouseCode, barcode barCode,customerNo, shjg shjg,current_num currentNum
FROM sales_summary WHERE 1=1

    AND item_code = #{itemCode}


    AND create_by = #{createBy}

SELECT COUNT(1) FROM sales_summary
WHERE match_qty != business_qty
AND create_by = #{createBy}

SELECT A.DOC_NO docNo, S.DOC_NO salesNo, U.UNIT_CODE unitCode, U.UNIT_NAME unitName, C.WAREHOUSE_CODE warehouseCode, D.ITEM_CODE itemCode, D.ITEM_NAME itemName, D.ITEM_SPECIFICATION itemSpec, SUM(B.BUSINESS_QTY) planQty, SUM(B.ISSUED_QTY) deliveryQty, SUM(ISNULL(B.BUSINESS_QTY, 0) - ISNULL(B.ISSUED_QTY, 0)) unDeliveryQty, Z.UDF021 binCode, (SELECT TOP 1 CUSTOMER_ORDER_NO FROM SALES_ORDER_DOC X LEFT JOIN SALES_ORDER_DOC_D Y ON X.SALES_ORDER_DOC_ID=Y.SALES_ORDER_DOC_ID LEFT JOIN SALES_ORDER_DOC_SD Z ON Y.SALES_ORDER_DOC_D_ID=Z.SALES_ORDER_DOC_D_ID LEFT JOIN SALES_DELIVERY_D K ON Z.SALES_ORDER_DOC_SD_ID=K.SOURCE_ID_ROid WHERE K.SALES_DELIVERY_ID=A.SALES_DELIVERY_ID) customerNo, P.PLANT_CODE shjg FROM SALES_DELIVERY A LEFT JOIN SALES_DELIVERY_D B ON A.SALES_DELIVERY_ID=B.SALES_DELIVERY_ID LEFT JOIN SALES_ORDER_DOC S ON S.SALES_ORDER_DOC_ID = B.SALES_ORDER_DOC_ID LEFT JOIN WAREHOUSE C ON B.WAREHOUSE_ID = C.WAREHOUSE_ID LEFT JOIN ITEM D ON D.ITEM_BUSINESS_ID = B.ITEM_ID LEFT JOIN ITEM_PLANT Z ON Z.ITEM_ID = D.ITEM_BUSINESS_ID LEFT JOIN UNIT U ON D.STOCK_UNIT_ID = U.UNIT_ID LEFT JOIN PLANT P ON P.PLANT_ID = A.PLANT_ID WHERE ISNULL(B.BUSINESS_QTY, 0) - ISNULL(B.ISSUED_QTY, 0) > 0
AND A.DOC_NO IN
#{docNo}
AND C.WAREHOUSE_CODE IN
#{warehouseCode}
AND ISNULL(D.ITEM_CODE,'') <> '' GROUP BY D.ITEM_CODE,D.ITEM_NAME,D.ITEM_SPECIFICATION,C.WAREHOUSE_CODE,U.UNIT_NAME,U.UNIT_CODE,A.DOC_NO,Z.UDF021,A.SALES_DELIVERY_ID,P.PLANT_CODE,S.DOC_NO ORDER BY D.ITEM_CODE

SELECT A.DOC_NO docNo, SUM(ISNULL(B.BUSINESS_QTY, 0)) businessQty, SUM(ISNULL(B.ISSUED_QTY, 0)) issuedQty FROM SALES_DELIVERY A LEFT JOIN SALES_DELIVERY_D B ON A.SALES_DELIVERY_ID = B.SALES_DELIVERY_ID LEFT JOIN ITEM D ON D.ITEM_BUSINESS_ID = B.ITEM_ID WHERE A.DOC_NO IN
#{docNo}
AND ISNULL(D.ITEM_CODE, '') LIKE '1%' GROUP BY A.DOC_NO

SELECT A.DOC_NO docNo, D.ITEM_CODE itemCode, D.ITEM_NAME itemName, D.ITEM_SPECIFICATION itemSpec, U.UNIT_CODE unitCode, U.UNIT_NAME unitName, SUM(B.BUSINESS_QTY) planQty, SUM(B.ISSUED_QTY) deliveryQty, SUM(B.BUSINESS_QTY - B.ISSUED_QTY) unDeliveryQty, SUM(ISNULL(S.qty, 0)) scannedQty, SUM(B.BUSINESS_QTY - B.ISSUED_QTY - ISNULL(S.qty, 0)) remainingQty, C.WAREHOUSE_CODE warehouseCode, ZP.UDF021 binCode, (SELECT TOP 1 CUSTOMER_ORDER_NO FROM SALES_ORDER_DOC X LEFT JOIN SALES_ORDER_DOC_D Y ON X.SALES_ORDER_DOC_ID = Y.SALES_ORDER_DOC_ID LEFT JOIN SALES_ORDER_DOC_SD Z2 ON Y.SALES_ORDER_DOC_D_ID = Z2.SALES_ORDER_DOC_D_ID LEFT JOIN SALES_DELIVERY_D K ON Z2.SALES_ORDER_DOC_SD_ID = K.SOURCE_ID_ROid WHERE K.SALES_DELIVERY_ID = A.SALES_DELIVERY_ID) customerNo, P.PLANT_CODE shjg FROM SALES_DELIVERY A LEFT JOIN SALES_DELIVERY_D B ON A.SALES_DELIVERY_ID = B.SALES_DELIVERY_ID LEFT JOIN WAREHOUSE C ON B.WAREHOUSE_ID = C.WAREHOUSE_ID LEFT JOIN ITEM D ON D.ITEM_BUSINESS_ID = B.ITEM_ID LEFT JOIN ITEM_PLANT ZP ON ZP.ITEM_ID = D.ITEM_BUSINESS_ID LEFT JOIN UNIT U ON D.STOCK_UNIT_ID = U.UNIT_ID LEFT JOIN PLANT P ON P.PLANT_ID = A.PLANT_ID LEFT JOIN ( SELECT docNo, itemCode, SUM(ISNULL(qty, 0)) AS qty FROM SalesOutboundTaskDetail WHERE 1=1
AND warehouseCode IN
#{w}
GROUP BY docNo, itemCode ) S ON S.docNo = A.DOC_NO AND S.itemCode = D.ITEM_CODE WHERE B.BUSINESS_QTY - B.ISSUED_QTY > 0 AND A.DOC_NO IN
#{item}
AND C.WAREHOUSE_CODE IN
#{w}
AND ISNULL(D.ITEM_CODE, '') <> '' GROUP BY D.ITEM_CODE, D.ITEM_NAME, D.ITEM_SPECIFICATION, C.WAREHOUSE_CODE, U.UNIT_NAME, U.UNIT_CODE, A.DOC_NO, ZP.UDF021, A.SALES_DELIVERY_ID, P.PLANT_CODE ORDER BY D.ITEM_CODE

SELECT id, barcode, warehouseCode, binCode, qty, docNo, salesNo, customerDocNo, unitCode, itemCode, itemName, itemSpec, orgNo, status, createTime, createBy, plan_qty planQty, synced, sync_time syncTime FROM SalesOutboundTaskDetail WHERE docNo = #{docNo}
AND createBy = #{createBy}
ORDER BY createTime DESC
